/* Renders a real router Link for "/"-style paths, or a plain anchor for
   "#"-style same-page hash links. */
function NavItem({ href, className, style, onClick, children }) {
  if (href.startsWith("/")) {
    return (
      <Link to={href} className={className} style={style} onClick={onClick}>
        {children}
      </Link>
    );
  }
  return (
    <a href={href} className={className} style={style} onClick={onClick}>
      {children}
    </a>
  );
}

